LAYER
  NAME "promedio_multianual_precipitacion_setiembre"
  GROUP "Precipitación multianual regiones de Cusco y Apurímac"
  STATUS off
  DATA "archivos/raster/promedio_multianual_precipitacion_setiembre.img"
  TYPE RASTER
  TRANSPARENCY 100
  DUMP true
  HEADER   "plantillas/inicio.html"
  TEMPLATE "plantillas/raster.html"
  FOOTER   "plantillas/fin.html" 
  PROJECTION
	"init=epsg:32718"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Precipitación multianual regiones de Cusco y Apurímac"
	"queryable" "true"
	"wms_metadataurl_type" "TC211"
	"wms_title" "Promedio multianual de la precipitación setiembre"
	"wms_abstract" "Promedio multianual de la precipitación setiembre - Copyright © Servicio Nacional de Meteorología e Hidrología - SENAMHI, fecha: Junio 2010 :: http://www.senamhi.gob.pe, Publicado por el Programa de Adaptación al Cambio Climático  - PACC Perú 2013 :: http://www.paccperu.org.pe"
	"wms_dataurl_href" "../descargar/promedio_multianual_precipitacion_setiembre.rar" 
	"autor" "© SENAMHI (Junio 2010) - PACC Perú"
	"wms_extent" "609253.687525827 8286928 1004503.68752583 8759678"
	"wms_srs" "EPSG:32718"
	"wms_include_items" "all"
	"wms_exclude_items" "value_0,red,green,blue"
	"force_imagetype" "jpeg"
  END
  CLASS
	NAME "Precipitación (mm)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "10 - 30"
    EXPRESSION ([pixel] >= 10 AND [pixel] < 30)
    COLOR 44 150 69
  END
  CLASS
	NAME "30 - 60"
    EXPRESSION ([pixel] >= 30 AND [pixel] < 60)
    COLOR 0 255 0
  END
  CLASS
	NAME "60 - 90"
    EXPRESSION ([pixel] >= 60 AND [pixel] < 90)
    COLOR 102 217 129
  END
  CLASS
	NAME "90 - 120"
    EXPRESSION ([pixel] >= 90 AND [pixel] < 120)
    COLOR 25 230 168
  END
  CLASS
	NAME "120 - 150"
    EXPRESSION ([pixel] >= 120 AND [pixel] < 150)
    COLOR 99 255 201
  END
  CLASS
	NAME "150 - 200"
    EXPRESSION ([pixel] >= 150 AND [pixel] < 200)
    COLOR 41 248 255
  END
  CLASS
	NAME "200 - 250"
    EXPRESSION ([pixel] >= 200 AND [pixel] < 250)
    COLOR 0 211 235
  END
  CLASS
	NAME "250 - 300"
    EXPRESSION ([pixel] >= 250 AND [pixel] < 300)
    COLOR 20 153 255
  END
  CLASS
	NAME "300 - 324"
    EXPRESSION ([pixel] >= 300 AND [pixel] <= 330)
    COLOR 20 5 255
  END
END # Layer